    // dp_up[i]: Maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is *greater* than the preceding element (i.e., ... < nums[i])
    // or it is the first element (length 1).
    const dp_up = new Array(n).fill(0);

    // dp_down[i]: Maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is *smaller* than the preceding element (i.e., ... > nums[i]).
    const dp_down = new Array(n).fill(0);

    let maxScore = 0;

    for (let i = 0; i < n; i++) {
        // Base case: A subsequence of length 1 ending at i always has score nums[i].
        dp_up[i] = nums[i];
        dp_down[i] = nums[i];

        // Iterate over all possible previous indices j < i
        for (let j = 0; j < i; j++) {
            // Check the distance constraint: i - j >= k
            if (i - j >= k) {
                // Case 1: nums[i] > nums[j] (Current step is 'up' compared to previous element)
                // The previous element nums[j] must have been the peak of a sequence,
                // meaning it must have been part of a sequence ending with a 'down' step (dp_down[j]).
                if (nums[i] > nums[j]) {
                    // We extend the sequence that ended at j with a peak (down step relative to its predecessor)
                    dp_up[i] = Math.max(dp_up[i], dp_down[j] + nums[i]);
                }

                // Case 2: nums[i] < nums[j] (Current step is 'down' compared to previous element)
                // The previous element nums[j] must have been a valley of a sequence,
                // meaning it must have been part of a sequence ending with an 'up' step (dp_up[j]).
                if (nums[i] < nums[j]) {
                    // We extend the sequence that ended at j with a valley (up step relative to its predecessor)
                    dp_down[i] = Math.max(dp_down[i], dp_up[j] + nums[i]);
                }
            }
        }

        // Update the overall maximum score considering all possible ending points and types
        maxScore = Math.max(maxScore, dp_up[i], dp_down[i]);
    }

    return maxScore;
}
